  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  // 开发环境使用 SQLite，生产环境改为 postgresql\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ==================== 用户与权限 ====================\n\nmodel User {\n  id           Int       @id @default(autoincrement())\n  username     String    @unique\n  email        String    @unique\n  passwordHash String\n  role         String    @default(\"MEMBER\") // ADMIN, MEMBER, VIEWER\n  teamId       Int?\n  team         Team?     @relation(fields: [teamId], references: [id])\n  createdAt    DateTime  @default(now())\n  lastLoginAt  DateTime?\n  preferences  String    @default(\"{}\") // JSON string\n  isActive     Boolean   @default(true)\n\n  // 关系\n  savedTitles        SavedTitle[]\n  savedCases         SavedCase[]\n  savedIntelligences SavedIntelligence[]\n  teamInvites        TeamInvite[]        @relation(\"InviteUser\")\n  activityLogs       ActivityLog[]\n\n  @@map(\"users\")\n}\n\nmodel Team {\n  id          Int      @id @default(autoincrement())\n  name        String\n  code        String   @unique\n  description String?\n  createdAt   DateTime @default(now())\n  isActive    Boolean  @default(true)\n\n  // 关系\n  members      User[]\n  invites      TeamInvite[]\n  sharedTitles SavedTitle[] @relation(\"TeamSaved\")\n\n  @@map(\"teams\")\n}\n\nmodel TeamInvite {\n  id        Int       @id @default(autoincrement())\n  teamId    Int\n  team      Team      @relation(fields: [teamId], references: [id])\n  email     String\n  token     String    @unique\n  role      String    @default(\"MEMBER\")\n  expiresAt DateTime\n  usedAt    DateTime?\n  createdAt DateTime  @default(now())\n  createdBy Int\n  creator   User      @relation(\"InviteUser\", fields: [createdBy], references: [id])\n\n  @@map(\"team_invites\")\n}\n\n// ==================== 情报数据 ====================\n\nmodel Intelligence {\n  id          Int       @id @default(autoincrement())\n  title       String\n  summary     String?\n  content     String?\n  source      String // 来源平台\n  sourceUrl   String?\n  category    String // INSURANCE, FINANCE, EDUCATION, TECH, SOCIAL, HEALTH\n  tags        String    @default(\"[]\") // JSON array string\n  hotScore    Int       @default(0)\n  publishTime DateTime?\n  createdAt   DateTime  @default(now())\n\n  // 关系\n  savedBy SavedIntelligence[]\n\n  @@index([category])\n  @@index([publishTime])\n  @@index([hotScore])\n  @@map(\"intelligence\")\n}\n\n// ==================== 爆款案例 ====================\n\nmodel ViralCase {\n  id             Int       @id @default(autoincrement())\n  platform       String // XHS, WX, DOUYIN, VIDEO, WEIBO, ZHIHU\n  title          String\n  content        String?\n  author         String?\n  authorUrl      String?\n  likesCount     Int       @default(0)\n  favoritesCount Int       @default(0)\n  commentsCount  Int       @default(0)\n  sharesCount    Int       @default(0)\n  url            String\n  coverImage     String?\n  tags           String    @default(\"[]\") // JSON array string\n  insuranceType  String? // 关联险种\n  viralScore     Float? // AI 计算的爆款分\n  analysis       String? // AI 爆款分析\n  publishedAt    DateTime?\n  createdAt      DateTime  @default(now())\n\n  // 关系\n  savedBy SavedCase[]\n\n  @@index([platform])\n  @@index([viralScore])\n  @@index([publishedAt])\n  @@map(\"viral_cases\")\n}\n\n// ==================== 标题收藏 ====================\n\nmodel SavedTitle {\n  id              Int       @id @default(autoincrement())\n  userId          Int\n  user            User      @relation(fields: [userId], references: [id])\n  keywords        String    @default(\"[]\") // JSON array string\n  generatedTitles String // JSON array string\n  finalTitle      String?\n  status          String    @default(\"DRAFT\") // DRAFT, USED, ARCHIVED\n  notes           String?\n  teamId          Int?\n  team            Team?     @relation(\"TeamSaved\", fields: [teamId], references: [id])\n  createdAt       DateTime  @default(now())\n  usedAt          DateTime?\n\n  @@map(\"saved_titles\")\n}\n\n// ==================== 收藏记录 ====================\n\nmodel SavedCase {\n  id        Int       @id @default(autoincrement())\n  userId    Int\n  user      User      @relation(fields: [userId], references: [id])\n  caseId    Int\n  case      ViralCase @relation(fields: [caseId], references: [id])\n  notes     String?\n  createdAt DateTime  @default(now())\n\n  @@unique([userId, caseId])\n  @@map(\"saved_cases\")\n}\n\nmodel SavedIntelligence {\n  id             Int          @id @default(autoincrement())\n  userId         Int\n  user           User         @relation(fields: [userId], references: [id])\n  intelligenceId Int\n  intelligence   Intelligence @relation(fields: [intelligenceId], references: [id])\n  notes          String?\n  createdAt      DateTime     @default(now())\n\n  @@unique([userId, intelligenceId])\n  @@map(\"saved_intelligences\")\n}\n\n// ==================== 采集任务 ====================\n\nmodel ScrapeTask {\n  id        Int       @id @default(autoincrement())\n  name      String\n  source    String\n  sourceUrl String\n  category  String // INSURANCE, FINANCE, EDUCATION, TECH, SOCIAL, HEALTH\n  schedule  String // cron 表达式\n  lastRunAt DateTime?\n  nextRunAt DateTime?\n  status    String    @default(\"ACTIVE\") // ACTIVE, PAUSED, ERROR\n  config    String? // JSON string\n  createdAt DateTime  @default(now())\n\n  @@map(\"scrape_tasks\")\n}\n\n// ==================== 操作日志 ====================\n\nmodel ActivityLog {\n  id         Int      @id @default(autoincrement())\n  userId     Int\n  user       User     @relation(fields: [userId], references: [id])\n  action     String // 操作类型\n  resource   String? // 资源类型\n  resourceId Int?\n  details    String? // JSON string\n  ip         String?\n  createdAt  DateTime @default(now())\n\n  @@index([userId])\n  @@index([createdAt])\n  @@map(\"activity_logs\")\n}\n",
